import React, { memo, useState } from 'react';
import './SectionHeader.css';

type ViewMode = 'beacon' | 'trends';

const VIEW_OPTIONS: { id: ViewMode; label: string; icon: string }[] = [
  { id: 'beacon', label: 'Beacon', icon: 'ðŸ“¡' },
  { id: 'trends', label: 'Trends', icon: 'ðŸ“ˆ' },
];

export const SectionHeader: React.FC = memo(() => {

  const [activeView, setActiveView] = useState<ViewMode>('beacon');

  return (
    <div className="section-header">
      <h2 className="section-header__title">Performance Overview</h2>
      <div className="view-toggle" role="group" aria-label="View mode">
        {VIEW_OPTIONS.map(({ id, label, icon }) => (
          <button
            key={id}
            className={`view-toggle__btn ${activeView === id ? 'view-toggle__btn--active' : ''}`}
            onClick={() => setActiveView(id)}
            aria-pressed={activeView === id}
          >
            <span aria-hidden="true">{icon}</span> {label}
          </button>
        ))}
      </div>
    </div>
  );
});

SectionHeader.displayName = 'SectionHeader';
